getMetrics(
  @Headers('authorization') authorization: string | undefined,
): string {
  const token = process.env['METRICS_TOKEN'];
  if (token) {
    const expected = `Bearer ${token}`;
    if (!authorization || authorization !== expected) {
      throw new UnauthorizedException('Invalid or missing METRICS_TOKEN');
    }
  }

server {
    listen 80;
    server_name orchestr-a.com www.orchestr-a.com _;

    # Security Headers (must be in server block to apply to all locations)
    # NOTE: Content-Security-Policy is intentionally NOT set at server level.
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;
    add_header Permissions-Policy "camera=(), microphone=(), geolocation=()" always;

proxy_set_header X-Real-IP $remote_addr;
proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
proxy_set_header X-Forwarded-Proto $http_x_forwarded_proto;
proxy_set_header X-Request-ID $request_id;

